'use client';

import { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useGSAP } from '@gsap/react';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

gsap.registerPlugin(ScrollTrigger);

export default function BookModel() {
  const bookRef = useRef<THREE.Group>(null);
  const coverRef = useRef<THREE.Mesh>(null);
  const opacityRef = useRef({ value: 1 });

  // 滚动时淡出书卷
  useGSAP(() => {
    if (!bookRef.current) return;

    ScrollTrigger.create({
      trigger: "body",
      start: "top top",
      end: "300px top",
      scrub: true,
      onUpdate: (self) => {
        // 在滚动前300px时淡出
        opacityRef.current.value = 1 - self.progress;
        if (bookRef.current) {
          bookRef.current.scale.setScalar(1 - self.progress * 0.3);
          bookRef.current.position.z = self.progress * -5; // 向后移动
        }
      }
    });
  }, []);

  // 浮动动画 - 参考旧版的float3D动画
  useFrame((state) => {
    if (bookRef.current) {
      const time = state.clock.getElapsedTime();
      // 3D浮动效果 - 模拟旧版的动画
      const yOffset = Math.sin(time * 0.5) * 0.3;
      const yRot = Math.sin(time * 0.3) * 0.1;
      const xRot = Math.sin(time * 0.4) * 0.05;
      
      bookRef.current.position.y = yOffset;
      bookRef.current.rotation.y = yRot;
      bookRef.current.rotation.x = xRot;

      // 应用透明度
      const opacity = opacityRef.current.value;
      bookRef.current.traverse((child) => {
        if ((child as THREE.Mesh).isMesh) {
          const mesh = child as THREE.Mesh;
          if (mesh.material) {
            const material = mesh.material as THREE.MeshStandardMaterial;
            material.opacity = opacity;
            material.transparent = opacity < 1;
          }
        }
      });
    }
  });

  return (
    <group ref={bookRef} position={[0, 0, 0]}>
      {/* 书卷主体 - 参考旧版的scroll-cover样式 */}
      <mesh ref={coverRef} position={[0, 0, 0]}>
        <boxGeometry args={[3.5, 5, 0.3]} />
        <meshStandardMaterial
          color="#8b4513"
          roughness={0.3}
          metalness={0.2}
          emissive="#6b4423"
          emissiveIntensity={0.1}
        />
      </mesh>

      {/* 书卷封面装饰纹理 - 模拟旧版的斜纹效果 */}
      <mesh position={[0, 0, 0.16]} rotation={[0, 0, Math.PI / 4]}>
        <planeGeometry args={[5, 5]} />
        <meshStandardMaterial
          color="#a0522d"
          roughness={0.5}
          transparent
          opacity={0.15}
        />
      </mesh>

      {/* 书卷封面基础层 */}
      <mesh position={[0, 0, 0.16]}>
        <planeGeometry args={[3.4, 4.9]} />
        <meshStandardMaterial
          color="#a0522d"
          roughness={0.5}
          transparent
          opacity={0.7}
        />
      </mesh>

      {/* 标题区域 - 金色背景 */}
      <mesh position={[0, 1.5, 0.17]}>
        <planeGeometry args={[2.5, 0.8]} />
        <meshStandardMaterial
          color="#d4af37"
          emissive="#d4af37"
          emissiveIntensity={0.3}
          transparent
          opacity={0.9}
        />
      </mesh>

      {/* 装饰线条 - 参考旧版的scroll-decoration */}
      <mesh position={[0, 0, 0.18]}>
        <planeGeometry args={[2.5, 0.05]} />
        <meshStandardMaterial
          color="#d4af37"
          emissive="#d4af37"
          emissiveIntensity={0.5}
        />
      </mesh>

      {/* 光晕效果 - 模拟旧版的光效 */}
      <pointLight position={[0, 0, 2]} intensity={0.6} color="#d4af37" />
      <pointLight position={[-2, 2, 3]} intensity={0.3} color="#fff" />
    </group>
  );
}

