'use client';

import { useRef, useMemo, useState } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { Line, useCursor } from '@react-three/drei';
import { useGSAP } from '@gsap/react';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

gsap.registerPlugin(ScrollTrigger);

// 节点数据结构
type NodeData = {
  id: number;
  position: [number, number, number];
  color: string;
  size: number;
  label?: string;
};

// 连线数据结构
type LinkData = {
  source: number; 
  target: number; 
  color: string;
};

export default function ArchitectureGraph() {
  const groupRef = useRef<THREE.Group>(null);
  const [activeState, setActiveState] = useState<0 | 1 | 2>(0); // 0: P, 1: O-P, 2: A-O-P

  // --- Configurations ---
  
  // P (Private): Simple 1v1
  const nodesP: NodeData[] = [
    { id: 0, position: [-1, 0, 0], color: '#1a1a1a', size: 0.3 },
    { id: 1, position: [1, 0, 0], color: '#b54949', size: 0.3 },
  ];
  const linksP: LinkData[] = [{ source: 0, target: 1, color: '#b54949' }];

  // O-P (Orchestrator): Star topology
  const nodesOP: NodeData[] = [
    { id: 0, position: [0, 1.2, 0], color: '#b54949', size: 0.5 }, // Big Orchestrator
    { id: 1, position: [-1.2, -0.8, 0], color: '#1a1a1a', size: 0.2 },
    { id: 2, position: [0, -0.8, 0.8], color: '#1a1a1a', size: 0.2 },
    { id: 3, position: [1.2, -0.8, 0], color: '#1a1a1a', size: 0.2 },
  ];
  const linksOP: LinkData[] = [
    { source: 0, target: 1, color: '#1a1a1a' },
    { source: 0, target: 2, color: '#1a1a1a' },
    { source: 0, target: 3, color: '#1a1a1a' },
  ];

  // A-O-P (Agent Mesh): Complex mesh
  const nodesAOP: NodeData[] = [
    { id: 0, position: [0, 0, 0], color: '#b54949', size: 0.4 }, // Core
    { id: 1, position: [1.5, 1, 0], color: '#1a1a1a', size: 0.2 },
    { id: 2, position: [-1.5, 1, 0], color: '#1a1a1a', size: 0.2 },
    { id: 3, position: [1, -1.5, 0], color: '#1a1a1a', size: 0.2 },
    { id: 4, position: [-1, -1.5, 0], color: '#1a1a1a', size: 0.2 },
    { id: 5, position: [0, 2, 0], color: '#b54949', size: 0.2 },
  ];
  const linksAOP: LinkData[] = [
    { source: 0, target: 1, color: '#b54949' },
    { source: 0, target: 2, color: '#b54949' },
    { source: 0, target: 3, color: '#b54949' },
    { source: 0, target: 4, color: '#b54949' },
    { source: 1, target: 5, color: '#1a1a1a' },
    { source: 2, target: 5, color: '#1a1a1a' },
  ];

  const currentNodes = activeState === 0 ? nodesP : activeState === 1 ? nodesOP : nodesAOP;
  const currentLinks = activeState === 2 ? linksAOP : activeState === 1 ? linksOP : linksP;

  // --- Animation Logic ---
  
  useGSAP(() => {
    if (!groupRef.current) return;

    // 1. VISIBILITY CONTROL
    // Hide initially
    gsap.set(groupRef.current.scale, { x: 0, y: 0, z: 0 });
    
    // Enter animation when Act 3 starts
    ScrollTrigger.create({
      trigger: "#act-3-container", // We will add this ID to the section in page.tsx
      start: "top center",
      end: "bottom top",
      onEnter: () => {
        gsap.to(groupRef.current!.scale, { x: 1, y: 1, z: 1, duration: 1, ease: "back.out(1.7)" });
      },
      onLeave: () => {
        gsap.to(groupRef.current!.scale, { x: 0, y: 0, z: 0, duration: 0.5 });
      },
      onEnterBack: () => {
        gsap.to(groupRef.current!.scale, { x: 1, y: 1, z: 1, duration: 1 });
      },
      onLeaveBack: () => {
        gsap.to(groupRef.current!.scale, { x: 0, y: 0, z: 0, duration: 0.5 });
      }
    });

    // 2. STATE SWITCHING
    // Trigger for P state
    ScrollTrigger.create({
      trigger: "#arch-p",
      start: "top center",
      end: "bottom center",
      onEnter: () => setActiveState(0),
      onEnterBack: () => setActiveState(0),
    });

    // Trigger for O-P state
    ScrollTrigger.create({
      trigger: "#arch-op",
      start: "top center",
      end: "bottom center",
      onEnter: () => setActiveState(1),
      onEnterBack: () => setActiveState(1),
    });

    // Trigger for A-O-P state
    ScrollTrigger.create({
      trigger: "#arch-aop",
      start: "top center",
      end: "bottom center",
      onEnter: () => setActiveState(2),
      onEnterBack: () => setActiveState(2),
    });
  }, []);

  // Continuous rotation
  useFrame((state, delta) => {
    if (groupRef.current) {
      groupRef.current.rotation.y += delta * 0.1;
    }
  });

  return (
    // Position shifted right (x=4) to avoid text overlap
    <group ref={groupRef} position={[4, 0, 0]}> 
      
      {/* Render Nodes */}
      {currentNodes.map((node, i) => (
        <mesh key={`node-${activeState}-${i}`} position={new THREE.Vector3(...node.position)}>
          <sphereGeometry args={[node.size, 32, 32]} />
          <meshStandardMaterial 
            color={node.color} 
            emissive={node.color}
            emissiveIntensity={0.4}
            roughness={0.3}
            metalness={0.8}
          />
        </mesh>
      ))}

      {/* Render Links */}
      {currentLinks.map((link, i) => {
        const start = new THREE.Vector3(...currentNodes[link.source].position);
        const end = new THREE.Vector3(...currentNodes[link.target].position);
        return (
          <Line
            key={`link-${activeState}-${i}`}
            points={[start, end]}
            color={link.color}
            lineWidth={3}
            transparent
            opacity={0.3}
          />
        );
      })}
      
    </group>
  );
}
